window.__QUIZ_DATA__=[{"id":"theory>Physics>2015>1>a","subject":"Physics","year":"2015","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"PROJECTILE MOTION :","question":"What is a projectile?","images":[],"marking_scheme":"A projectile is an object which can be fashioned to form a parabola. The the trajectory of a projectile is usually parabolic or curvi-linear.","marks":"2","difficulty":"3"},{"id":"theory>Physics>2015>1>b","subject":"Physics","year":"2015","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"PROJECTILE MOTION :","question":"Give the reason why the horizontal component of the velocity of a projectile remains the same at every point of its flight.","images":[],"marking_scheme":"- Zero air resistance   - Zero horizontal forces; hence no acceleration and no change in the velocity","marks":"1","difficulty":"2"},{"id":"theory>Physics>2015>2","subject":"Physics","year":"2015","type":"Theory","sub_label":"2","group":"FINAL","topic":"PROJECTILE MOTION :","question":"A body is projected at an angle of 30o to the horizontal with a velocity of 150ms-1. Calculate the time it takes the greatest height. [Take g = 10ms-2 and neglect air resistance]","images":[],"marking_scheme":"Given:  \u03b8 = 30o; u = 150ms-1; t = ? and g = 10ms-2  \u2192 The times taken to reach maximum height, t = ?  recall that: t = usin\u03b8/g = 150 x Sin30o/10    = 75/10    = 7.5s","marks":"3","difficulty":"3"},{"id":"theory>Physics>2015>3","subject":"Physics","year":"2015","type":"Theory","sub_label":"3","group":"","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"A wire of length 2.00m and radius 1.0mm is stretched by 25.00mm on application of a force of 103N. Calculate the young's modulus for the wire.","images":[],"marking_scheme":"Given:  L = 2m r = 1mm = 1 x 10-3m. e = 25mm = 25 x 10-3m  F = 100N   Young modules, E = FL/Ae = ?    Area, A = \u03c0r2 = 3.142 x (10-3)2 = 3.142x10-6  =1000 x 23.142 x 10-6 x 25 x 10-3   = 2.55 x 1010 NM-2","marks":"3","difficulty":"3"},{"id":"theory>Physics>2015>4","subject":"Physics","year":"2015","type":"Theory","sub_label":"4","group":"CLOSENESS","topic":"HEAT ENERGY : HEAT TRANSFER","question":"State three ways of increasing the rate of cooling of a cup of hot tea .","images":[],"marking_scheme":"- Increasing the surface area by blowing   - Mixing   - Stirring","marks":"4","difficulty":"1"},{"id":"theory>Physics>2015>5>a","subject":"Physics","year":"2015","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS","question":"What is doping in a semi-conductor?","images":[],"marking_scheme":"Doping can be defined as the scope or the process of adding impure substances  to semiconductors in order to alter their properties","marks":"3","difficulty":"2"},{"id":"theory>Physics>2015>5>b","subject":"Physics","year":"2015","type":"Theory","sub_label":"b","group":"","topic":"ELECTRICAL CONDUCTION THROUGH MATERIALS [ELECTRONIC] :","question":"Draw the symbol for OR gate.","images":["data:image/png;base64,"],"marking_scheme":"Symbol of OR - Gate","marks":"2","difficulty":"1"},{"id":"theory>Physics>2015>6>a","subject":"Physics","year":"2015","type":"Theory","sub_label":"a","group":"","topic":"ELECTRIC FIELD : ELECTRIC CIRCUIT","question":"The circuit above consists of an a.c voltage input, a diode, a resistor and a voltmeter. Identify the circuit","images":["data:image/png;base64,"],"marking_scheme":"The circuit is half -wave rectifier","marks":"3","difficulty":"2"},{"id":"theory>Physics>2015>6>b","subject":"Physics","year":"2015","type":"Theory","sub_label":"b","group":"","topic":"ELECTRIC FIELD : ELECTRIC CIRCUIT","question":"The circuit above consists of an a.c voltage input, a diode, a resistor and a voltmeter. Draw the waveform for the output voltage.","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"","marks":"2","difficulty":"3"},{"id":"theory>Physics>2015>7>a","subject":"Physics","year":"2015","type":"Theory","sub_label":"a","group":"","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"Write the de-Broglie equation.","images":[],"marking_scheme":"7(a) de Broglie's equation is given as   \u03bb = h/p = h/mv     h = planck's constant     * It should be noted h = 6.63 x 1034Js  mass of the wave particle = m(in kg)  velocity of wave particle = v(in ms-1)  Momentum of wave particle = P(in kgms-1)","marks":"2","difficulty":"2"},{"id":"theory>Physics>2015>7>b","subject":"Physics","year":"2015","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"Explain the significance of the equation","images":[],"marking_scheme":"The significance of the equation is that it shows that matter has a dual nature, it can exist as a wave and as a particle.","marks":"1","difficulty":"3"},{"id":"theory>Physics>2015>8>a>i","subject":"Physics","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION","question":"Define uniform acceleration","images":[],"marking_scheme":"Uniform acceleration is the acceleration of a body when it is under going a constant time rate of change in velocity","marks":"1","difficulty":"1"},{"id":"theory>Physics>2015>8>a>ii","subject":"Physics","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"MOTION : SIMPLE IDEAS OF CIRCULAR MOTION","question":"Write an equation that relates linear velocity, angular velocity and radius of path in circular motion.","images":[],"marking_scheme":"V = wr  v = linear/Tangential velocity   w = Angular velocity   r = Radius","marks":"1","difficulty":"2"},{"id":"theory>Physics>2015>8>b","subject":"Physics","year":"2015","type":"Theory","sub_label":"b","group":"","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"Two forces 30N and 40N act at right angles to each other. Determine by scale drawing, the magnitude and direction of the resultant force, using a scale of 1cm of 5N.","images":["data:image/png;base64,"],"marking_scheme":"Scale: 1 cm to 5 N    30N = 6cm and 40N = 8cm","marks":"1","difficulty":"3"},{"id":"theory>Physics>2015>8>c","subject":"Physics","year":"2015","type":"Theory","sub_label":"c","group":"","topic":"FLUID AT REST : EQUILIBRIUM OF BODIES: LAW OF FLOTATION","question":"Explain why ships are usually refilled with sand and water after they have been emptied of their cargo.","images":[],"marking_scheme":"A floating ship is balanced by its weight and the upthrust becomes greater than the weight of the ship when the ship is refilled with sand  and water to restore it stability  and attains its equilibrium","marks":"1","difficulty":"2"},{"id":"theory>Physics>2015>8>d>i","subject":"Physics","year":"2015","type":"Theory","sub_label":"i","group":"","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"A crate of drinks of mass 20kg is placed on a plane inclined at 30o to the horizontal. If the crate slides down with a constant speed, calculate the Co-efficient of kinetic friction","images":["data:image/png;base64,"],"marking_scheme":"u = tan\u03f4   = tan30   = 0.5774","marks":"2","difficulty":"3"},{"id":"theory>Physics>2015>8>d>ii","subject":"Physics","year":"2015","type":"Theory","sub_label":"ii","group":"FINAL","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"A crate of drinks of mass 20kg is placed on a plane inclined at 30o to the horizontal. If the crate slides down with a constant speed, calculate the Magnitude of the frictional force acting on the crate   [g = 10ms-2]","images":[],"marking_scheme":"Co-efficient of friction = tan\u03b8   = tan30o = 0.58     (ii) Frictional force   f = UR = u x Wcos\u03b8   f = 0.58 x 250cos30o  = 0.58 x 250 x 0.8660  = 125.57N","marks":"2","difficulty":"3"},{"id":"theory>Physics>2015>9>a","subject":"Physics","year":"2015","type":"Theory","sub_label":"a","group":"","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION","question":"Define specific latent heat of vaporization?","images":[],"marking_scheme":"The specific latent heat of vaporization is the quantity of heat that is required to change the state of a unit mass of a liquid to a gaseous state","marks":"1","difficulty":"1"},{"id":"theory>Physics>2015>9>b>i","subject":"Physics","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ENERGY : WORLD ENERGY RESOURCES","question":"What are renewable energy sources?","images":[],"marking_scheme":"Renewable energy sources are the sources where replaceable energy being used up can be gotten or found.","marks":"1","difficulty":"1"},{"id":"theory>Physics>2015>9>b>ii","subject":"Physics","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ENERGY : WORLD ENERGY RESOURCES","question":"List four renewable energy sources.","images":[],"marking_scheme":"The four sources include: - Sun - Wind - Water - Garbage (Biomass)","marks":"1","difficulty":"1"},{"id":"theory>Physics>2015>9>c","subject":"Physics","year":"2015","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"Explain why tomatoes keep longer when kept in a moist jute bag in a clay pot.","images":[],"marking_scheme":"A moist jute bag in a clay pot is always wet and the temperature is low and cool. The tomatoes kept in this bag are being preserved and with the low temperature, heat loss or gain will be neglected.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2015>9>d>i","subject":"Physics","year":"2015","type":"Theory","sub_label":"i","group":"FINAL","topic":"FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY","question":"A box has a volume of 0.28m3 and is 70% filled with iron fillings at 25oC. Calculate the total mass of the iron fillings  [Density of iron = 8.00 x 103Kgm-3, specific latent heat of fusion of iron = 1.38 x 105JKg-1, specific heat capacity of iron = 460JKg-1K-1, melting point of iron = 1500oC]","images":[],"marking_scheme":"Given:  Volume V = 0.28m3  The iron fillings volume = 70/100 x 0.28 = 0.196cm3    (I) Total mass, m = ?  Density = mass/volume     Mass = Density x volume   Mass = 8000 x 0.196 = 1568kg","marks":"2","difficulty":"3"},{"id":"theory>Physics>2015>9>d>ii","subject":"Physics","year":"2015","type":"Theory","sub_label":"ii","group":"","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF FUSION","question":"A box has a volume of 0.28m3 and is 70% filled with iron fillings at 25oC. Calculate the energy required to melt 10% of the iron fillings.   [Density of iron = 8.00 x 103Kgm-3, specific latent heat of fusion of iron = 1.38 x 105JKg-1, specific heat capacity of iron = 460JKg-1K-1, melting point of iron = 1500oC]","images":[],"marking_scheme":"Energy = ml + mc\u03b8   = (1568 x 1.38 x 105) + (1568 x 460 + (1500-25))  = 216384000 + 1.06x109  = 1.28 x 109J","marks":"2","difficulty":"3"},{"id":"theory>Physics>2015>10>a>i","subject":"Physics","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"SOUND WAVES : RESONANCE","question":"What is resonance?","images":[],"marking_scheme":"Resonance is the effect felt/observed when a body vibrating with its own natural frequency transfers its frequency to the bodies around it, such that they all vibrate with the same frequency.","marks":"1","difficulty":"1"},{"id":"theory>Physics>2015>10>a>ii","subject":"Physics","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"SOUND WAVES : RESONANCE","question":"State two examples of resonance.","images":[],"marking_scheme":"- Vibrating turning fork   - Soldiers marching on a bridge","marks":"2","difficulty":"1"},{"id":"theory>Physics>2015>10>a>iii","subject":"Physics","year":"2015","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"SOUND WAVES : CHARACTERISTICS OF SOUND","question":"Differentiate between loudness and intensity of sound","images":[],"marking_scheme":"Intensity can be described as the rate of flow of energy per unit time; while loudness is the magnitude of the sensation resulting from a sound reaching the ear.","marks":"1","difficulty":"2"},{"id":"theory>Physics>2015>10>b","subject":"Physics","year":"2015","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"When a ray is refracted through a rectangular glass prism, which of the following properties of the ray will change?    Wavelength, frequency and speed.","images":[],"marking_scheme":"Wavelength and speed will change and the frequency will remain constant.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2015>10>c>i","subject":"Physics","year":"2015","type":"Theory","sub_label":"i","group":"","topic":"PROPERTIES OF WAVES : DIFFRACTION","question":"Copy the diagram above in your answer booklet.","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"1"},{"id":"theory>Physics>2015>10>c>ii","subject":"Physics","year":"2015","type":"Theory","sub_label":"ii","group":"","topic":"PROPERTIES OF WAVES : DIFFRACTION","question":"On the copied diagram, sketch the pattern of the waves immediately after passing through the opening.","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"","marks":"2","difficulty":"3"},{"id":"theory>Physics>2015>10>d>i","subject":"Physics","year":"2015","type":"Theory","sub_label":"i","group":"FINAL","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"A diverging lens of focal length 18.0m is used to view a shark that is 90.0m away from the lens. If the image formed is 1.0m long, calculate the image distance.","images":[],"marking_scheme":"10(d) Given:  Focal length, f = 18m  Objective size, u = 90m  Image size, v = V = unknown   Image height, h = 1m     Recall that:  -1/t = 1/u+1/v     -1/18 = 1/90+1/v     -1/18 - 1/90 = 1/v     -90-18/(90)(18)    V = 90x18/-108 = -90/6 = -15m     The negative value of v indicates that v is a virtual image.    m = v/u = Image height/Object height     15/90 = 1/x     x = 6cm     \u2234Object height = x = 6cm","marks":"1","difficulty":"3"},{"id":"theory>Physics>2015>10>d>ii","subject":"Physics","year":"2015","type":"Theory","sub_label":"ii","group":"FINAL","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES","question":"A diverging lens of focal length 18.0m is used to view a shark that is 90.0m away from the lens. If the image formed is 1.0m long, calculate the length of the shark.","images":[],"marking_scheme":"Given:  Focal length, f = 18m  Objective size, u = 90m  Image size, v = V = unknown   Image height, h = 1m     Recall that:  -1/t = 1/u+1/v     -1/18 = 1/90+1/v     -1/18 - 1/90 = 1/v     -90-18/(90)(18)    V = 90x18/-108 = -90/6 = -15m     The negative value of v indicates that v is a virtual image.    m = v/u = Image height/Object height     15/90 = 1/x     x = 6cm     \u2234Object height = x = 6cm","marks":"1","difficulty":"3"},{"id":"theory>Physics>2015>11>a>i","subject":"Physics","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELECTRIC FIELD : COULOMB\u2019S LAW","question":"Define the coulomb","images":[],"marking_scheme":"Coulomb is the quantity of electricity passing a section of conductor in one second when the current is one ampere","marks":"2","difficulty":"1"},{"id":"theory>Physics>2015>11>a>ii","subject":"Physics","year":"2015","type":"Theory","sub_label":"ii","group":"","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"Define resistance?","images":[],"marking_scheme":"Resistance is the driving force that creates opposition to the flow of current in a circuit","marks":"2","difficulty":"1"},{"id":"theory>Physics>2015>11>b","subject":"Physics","year":"2015","type":"Theory","sub_label":"b","group":"","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"State the three effects of an electric current","images":[],"marking_scheme":"- Chemical effect  - Magnetic effect   - Heating effect","marks":"2","difficulty":"2"},{"id":"theory>Physics>2015>11>c>i","subject":"Physics","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELECTRIC FIELD : ELECTRIC CIRCUIT","question":"State the standard international colour convention for the insulating material covering this electrical wire in a three-pin plug.  live","images":[],"marking_scheme":"Live - Red/Brown   Neutral - Blue/Black   Earth - Yellow/Green","marks":"2","difficulty":"2"},{"id":"theory>Physics>2015>11>c>ii","subject":"Physics","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"State the standard international colour convention for the insulating material covering this electrical wire in a three-pin plug. Neutral","images":[],"marking_scheme":"Live - Red/Brown   Neutral - Blue/Black   Earth - Yellow/Green","marks":"2","difficulty":"1"},{"id":"theory>Physics>2015>11>c>iii","subject":"Physics","year":"2015","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"State the standard international colour convention for the insulating material covering this electrical wire in a three-pin plug. earth","images":[],"marking_scheme":"Live - Red/Brown   Neutral - Blue/Black   Earth - Yellow/Green","marks":"2","difficulty":"1"},{"id":"theory>Physics>2015>11>d>i","subject":"Physics","year":"2015","type":"Theory","sub_label":"i","group":"","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"A water melon of mass 5.0kg is suspended on a uniform rod of mass 4.0kg and 4.0m long as illustrated in the diagram above. If the rod is in equilibrium by the action of the force between the charges +q and -q, calculate the anticlockwise moment   [g = 10ms-2]","images":["data:image/png;base64,"],"marking_scheme":"F = kq2/r2 = 9x102/(2.5)2 = 1.44x109q2N    Clockwise moment   Cw=4gl2+Kq2l3(l2)   =4x10x1+8.99 x 109 x q23(2.5)2   = 40 + 4.315 x 109 x q2  Anticlockwise moment  = 5gl1   = 5 x 10 x 1  =  50NM","marks":"2","difficulty":"3"},{"id":"theory>Physics>2015>11>d>ii","subject":"Physics","year":"2015","type":"Theory","sub_label":"ii","group":"","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"A water melon of mass 5.0kg is suspended on a uniform rod of mass 4.0kg and 4.0m long as illustrated in the diagram above. If the rod is in equilibrium by the action of the force between the charges +q and -q, calculate the value of q.   [g = 10ms-2]","images":["data:image/png;base64,"],"marking_scheme":"Sum of the clockwise moment = sum of anticlockwise movement   40 + 43 + 5 +x109 x q2 = 50  q=\u221a104.315 x 109","marks":"1","difficulty":"3"},{"id":"theory>Physics>2015>12>a","subject":"Physics","year":"2015","type":"Theory","sub_label":"a","group":"","topic":"STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS","question":"Define nucleon number","images":[],"marking_scheme":"Nucleon number is the total number of proton of protons and neutrons in an atom of an element","marks":"3","difficulty":"1"},{"id":"theory>Physics>2015>12>b>i","subject":"Physics","year":"2015","type":"Theory","sub_label":"i","group":"FINAL","topic":"STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS","question":"A radioactive isotope of Americium (Am - 241) decays into  nucleus of Neptunium (Np - 237) and an alpha (\u03b1) particle as shown in the nuclear equation below.   24195Am \u2192 237CNp + ba\u03b1    State the number of neutrons in the nucleus of Americium -241.","images":[],"marking_scheme":"(b) 24195Am \u2192 237cNp + ba\u221d     Recall that ba\u221d  = 42He    24195Am \u2192 2372Np + 42He     (ii)95 = c+2; c = 93   (i) Number of neutrons = 241 - 95 = 146","marks":"2","difficulty":"2"},{"id":"theory>Physics>2015>12>b>ii","subject":"Physics","year":"2015","type":"Theory","sub_label":"ii","group":"","topic":"STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS","question":"A radioactive isotope of Americium (Am - 241) decays into  nucleus of Neptunium (Np - 237) and an alpha (\u03b1) particle as shown in the nuclear equation below.   24195Am \u2192 237CNp + ba\u03b1    Determine the values of a, b and c.","images":[],"marking_scheme":"(b) 24195Am \u2192 237cNp + ba\u221d     Recall that ba\u221d  = 42He    24195Am \u2192 2372Np + 42He     (ii)95 = c+2; c = 93   (i) Number of neutrons = 241 - 95 = 146","marks":"3","difficulty":"3"},{"id":"theory>Physics>2015>12>c>i","subject":"Physics","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"Why are \u03b3-rays not deflected by electromagnetic fields?","images":[],"marking_scheme":"\u03b3-rays have no mass and no charge. Electromagnetic field has no effect on them.   20882Pb and 21282Pb or  21284Po and 21684Po or  22488Ra and 28888Ra or  28890Th and 23290Th","marks":"2","difficulty":"2"},{"id":"theory>Physics>2015>12>c>ii","subject":"Physics","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"State two properties of gamma rays that make them suitable for sterilizing medical equipment.","images":[],"marking_scheme":"- High penetrating energy that makes it pass through tissues and kill virus and bacteria   - Ionization energy: They are ionizing radiations.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2015>12>d","subject":"Physics","year":"2015","type":"Theory","sub_label":"d","group":"FINAL","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"A sample of radioactive substance was found to be left with 1/32 of its initial count rate after 110 years. Calculate its decay constant.","images":[],"marking_scheme":"Remaining = 1/32     After first half life = N/2     Second = (N/2)x1/2 = N/4     Third (N/4) x 1/2 = N/8     Fourth (N/8) x 1/2 = N/16     Fifth (N/16) x 1/2 = n/32     100/5 = 22 years     \u2234 T1/2(half-life) = 22years   Decay constant = 0.693/T1/2 = 0.693/22 = 0.0315sec-1","marks":"3","difficulty":"3"}];